VkDevice device = VK_NULL_HANDLE;
VkPipelineCache dstCache = VK_NULL_HANDLE;
uint32_t srcCacheCount = 0;
VkPipelineCache* srcCaches = nullptr;

VkResult result = vkMergePipelineCaches(
    device,
    dstCache,
    srcCacheCount,
    srcCaches
);

if (result == VK_SUCCESS) {
    // تمت العملية بنجاح ويمكن متابعة العمل بعد vkMergePipelineCaches
} else {
    // عالج رمز الخطأ أو أعد تهيئة الموارد المطلوبة
}

